import pytest

from calc import divide, percent


class TestDivide:
    """Tests for the divide function."""

    def test_divide_basic(self):
        assert divide(10, 2) == 5

    def test_divide_result_is_float(self):
        result = divide(5, 2)
        assert result == 2.5
        assert isinstance(result, float)

    def test_divide_positive_numbers(self):
        assert divide(100, 4) == 25

    def test_divide_negative_numbers(self):
        assert divide(-10, 2) == -5
        assert divide(10, -2) == -5
        assert divide(-10, -2) == 5

    def test_divide_decimals(self):
        assert divide(7.5, 2.5) == 3.0

    def test_divide_one(self):
        assert divide(5, 1) == 5

    def test_divide_fraction(self):
        assert divide(1, 4) == 0.25

    def test_divide_by_zero_raises(self):
        with pytest.raises(ValueError, match="cannot divide by zero"):
            divide(10, 0)

    def test_divide_zero_by_number(self):
        assert divide(0, 5) == 0

    def test_divide_large_numbers(self):
        assert divide(1000000, 1000) == 1000


class TestPercent:
    """Tests for the percent function."""

    def test_percent_basic(self):
        assert percent(50, 100) == 50

    def test_percent_quarter(self):
        assert percent(25, 100) == 25

    def test_percent_one_third(self):
        result = percent(1, 3)
        assert abs(result - 33.333333) < 0.001

    def test_percent_all(self):
        assert percent(100, 100) == 100

    def test_percent_half(self):
        assert percent(50, 200) == 25

    def test_percent_small_number(self):
        assert percent(1, 100) == 1

    def test_percent_decimal_input(self):
        assert percent(7.5, 50) == 15

    def test_percent_zero_part(self):
        assert percent(0, 100) == 0

    def test_percent_zero_whole_raises(self):
        with pytest.raises(ValueError, match="cannot divide by zero"):
            percent(50, 0)

    def test_percent_negative_part(self):
        result = percent(-50, 100)
        assert result == -50

    def test_percent_negative_whole(self):
        result = percent(50, -100)
        assert result == -50

    def test_percent_both_negative(self):
        result = percent(-50, -100)
        assert result == 50

    def test_percent_large_number_result(self):
        assert percent(1, 2) == 50

    def test_percent_very_small_result(self):
        result = percent(1, 1000)
        assert result == 0.1

    def test_percent_greater_than_100(self):
        assert percent(150, 100) == 150

import pytest

from metrics import mean


class TestMean:
    """Tests for the mean function."""

    def test_mean_basic(self):
        assert mean([1, 2, 3]) == 2

    def test_mean_two_values(self):
        assert mean([10, 20]) == 15

    def test_mean_single_value(self):
        assert mean([5]) == 5

    def test_mean_negative_numbers(self):
        assert mean([-1, -2, -3]) == -2

    def test_mean_mixed_positive_negative(self):
        assert mean([-5, 5]) == 0

    def test_mean_decimals(self):
        result = mean([1.5, 2.5, 3.0])
        assert abs(result - 2.333333) < 0.001

    def test_mean_large_numbers(self):
        assert mean([1000, 2000, 3000]) == 2000

    def test_mean_zero_values(self):
        assert mean([0, 0, 0]) == 0

    def test_mean_mixed_with_zero(self):
        assert mean([0, 1, 2]) == 1

    def test_mean_fractional_result(self):
        result = mean([1, 2, 3, 4, 5])
        assert result == 3.0

    def test_mean_returns_float(self):
        result = mean([1, 2, 3])
        assert isinstance(result, float)

    def test_mean_empty_list_raises(self):
        with pytest.raises(ValueError, match="no values"):
            mean([])

    def test_mean_very_small_numbers(self):
        result = mean([0.1, 0.2, 0.3])
        abs(result - 0.2) < 0.001

    def test_mean_many_values(self):
        values = list(range(1, 101))  # 1 to 100
        assert mean(values) == 50.5

    def test_mean_identical_values(self):
        assert mean([7, 7, 7, 7]) == 7

    def test_mean_odd_number_of_values(self):
        result = mean([10, 20, 30, 40, 50])
        assert result == 30

